Rules.InvariantScript:
// check if job is closed
If(
    // open the closed job modal
    gblRecordJobCurrent.Completed = gblOptionSets.Job.CompletedJob.Yes And locReOpenClosedJobDecisionMade = false,
    UpdateContext({locShowClosedJobPrompt: true}),
    With(
        {
            varType: "colCdsJobs",
            varRecordRef: gblRecordJobCurrent.Job
        },
        If(
            IsBlank(
                LookUp(
                    colAUDRecords,
                    Type = varType
                    And RecordRef = varRecordRef
                )
            ),
            Collect(
                colAUDRecords,
                {
                    Type: varType,
                    RecordRef: varRecordRef,
                    Job: gblRecordJobCurrent.Job,
                    Operation: "U"
                }
            )
        )
    );
    If(
        gblAppLoadOffline,
        SaveData(
            colAUDRecords,
            "localAUDRecords"
        )
    )
)

// change the jobs completed field to 'No'
Patch(
    colCdsJobs,
    LookUp(
        colCdsJobs,
        appJobIDText = gblRecordJobCurrent.appJobIDText
    ),
    {Completed: gblOptionSets.Job.CompletedJob.No}
);
Set(
    gblRecordJobCurrent,
    LookUp(
        colCdsJobs,
        appJobIDText = gblRecordJobCurrent.appJobIDText
    )
);
// hide the prompt
UpdateContext(
    {
        locShowClosedJobPrompt: false,
        locReOpenClosedJobDecisionMade: true
    }
);
// unsaved job
Collect(
    colAUDRecords,
    {
        Type: "colCdsJobs",
        RecordRef: gblRecordJobCurrent.Job,
        Job: gblRecordJobCurrent.Job,
        Operation: "U"
    }
);
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    )
)

If(
    IsBlank(
        Text(
            gblRecordJobCurrent.'Rescission Date',
            "[$-en-US]mmm d"
        )
    ),
    "None",
    Text(
        gblRecordJobCurrent.'Rescission Date',
        "[$-en-US]mmm d"
    )
)

With(
    {
        varPrimary: gblRecordJobCurrent.'Primary Contact',
        varSecondary: gblRecordJobCurrent.'Secondary Contact'
    },
    Concatenate(
        varPrimary.'Full Name',
        If(
            IsBlankOrError(varSecondary),
            Blank(),
            Concatenate(
                "& ",
                varSecondary.'Full Name'
            )
        )
    )
)
